select count(*) from postgres.comments as c, postgres.votes as v, postgres.badges as b, postgres.users as u where u.id = b.userid and u.id = c.userid and u.id = v.userid and c.score=1 and c.creationdate>=timestamp '2010-08-27 14:12:07' and v.votetypeid=5 and v.creationdate>=timestamp '2010-07-19 00:00:00' and v.creationdate<=timestamp '2014-09-13 00:00:00' and b."date"<=timestamp '2014-08-19 10:32:13' and u.reputation>=1;
